'use client'
import { cn, useClipboard, useSignals } from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { type CodeLang, tokenize } from './highlight'
import styles from './code-snippet.module.css'

export type { CodeLang }

export interface CodeSnippetProps {
  /** The code to display (and copy). */
  code: string
  /** inline = a <code> span; single = one-line <pre>; multi = multi-line <pre>. */
  variant?: 'inline' | 'single' | 'multi'
  /**
   * Enables lightweight, dependency-free syntax highlighting for the block
   * variants. Omit for plain text. Inline code is never highlighted.
   */
  language?: CodeLang
  /**
   * Renders terminal-window chrome (a title bar with traffic-light dots). Pair
   * with `language="bash"` for a shell transcript. Block variants only.
   */
  terminal?: boolean
  /** Optional label shown in the terminal title bar. */
  title?: string
  /** Show line numbers (multi only; ignored when `language` is set). */
  showLineNumbers?: boolean
  /** Show the copy-to-clipboard button. Defaults true for single/multi, false for inline. */
  showCopyButton?: boolean
  labels?: { copy?: string; copied?: string }
  className?: string
}

/** Syntax-highlighted `<code>` body — one span per token, coloured via `data-tok`. */
function Highlighted({ code, language }: { code: string; language: CodeLang }) {
  return (
    <code className={styles['code']}>
      {tokenize(code, language).map((tok, i) =>
        tok.type === 'text' ? (
          // eslint-disable-next-line react/no-array-index-key
          <span key={i}>{tok.value}</span>
        ) : (
          // eslint-disable-next-line react/no-array-index-key
          <span key={i} data-tok={tok.type}>
            {tok.value}
          </span>
        ),
      )}
    </code>
  )
}

/**
 * Code display with optional, dependency-free syntax highlighting. `inline`
 * renders a `<code>` chip in flowing text; `single` a horizontally scrolling
 * one-liner; `multi` a block with optional line numbers. Pass `language` to
 * colour bash/css/js/ts, and `terminal` for shell-window chrome. An optional
 * copy button uses `useClipboard` to copy the raw `code`.
 */
export function CodeSnippet({
  code,
  variant = 'single',
  language,
  terminal = false,
  title,
  showLineNumbers,
  showCopyButton,
  labels,
  className,
}: CodeSnippetProps) {
  useSignals()
  const { copied, copy } = useClipboard()
  const copyLabel = labels?.copy ?? t(builtin.codeSnippet.copy)
  const copiedLabel = labels?.copied ?? t(builtin.codeSnippet.copied)
  const withCopy = showCopyButton ?? variant !== 'inline'

  const copyButton = withCopy ? (
    <button
      type="button"
      aria-label={copied.value ? copiedLabel : copyLabel}
      data-state={copied.value ? 'copied' : 'idle'}
      className={styles['copy']}
      onClick={() => void copy(code)}
    >
      {copied.value ? (
        <svg aria-hidden="true" viewBox="0 0 16 16" className={styles['icon']}>
          <path
            d="M13.5 4.5 6 12 2.5 8.5"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
        </svg>
      ) : (
        <svg aria-hidden="true" viewBox="0 0 16 16" className={styles['icon']}>
          <rect
            x="5.5"
            y="5.5"
            width="8"
            height="8"
            rx="1.5"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
          />
          <path
            d="M3.5 10.5h-1a1 1 0 0 1-1-1v-7a1 1 0 0 1 1-1h7a1 1 0 0 1 1 1v1"
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
          />
        </svg>
      )}
    </button>
  ) : null

  if (variant === 'inline') {
    return (
      <span className={cn(styles['root'], className)} data-variant="inline">
        <code className={styles['inlineCode']}>{code}</code>
        {copyButton}
      </span>
    )
  }

  const lines = code.split('\n')
  const withNumbers = variant === 'multi' && showLineNumbers && !language

  return (
    <div
      className={cn(styles['root'], className)}
      data-variant={variant}
      data-terminal={terminal ? '' : undefined}
    >
      {terminal && (
        <div className={styles['bar']} aria-hidden="true">
          <span className={styles['dots']}>
            <span className={styles['dot']} />
            <span className={styles['dot']} />
            <span className={styles['dot']} />
          </span>
          {title && <span className={styles['title']}>{title}</span>}
        </div>
      )}
      <pre className={styles['pre']}>
        {withNumbers ? (
          <code className={styles['code']}>
            {lines.map((line, i) => (
              // eslint-disable-next-line react/no-array-index-key
              <span key={i} className={styles['line']}>
                <span aria-hidden="true" className={styles['lineNumber']}>
                  {i + 1}
                </span>
                <span className={styles['lineText']}>{line}</span>
              </span>
            ))}
          </code>
        ) : language ? (
          <Highlighted code={code} language={language} />
        ) : (
          <code className={styles['code']}>{code}</code>
        )}
      </pre>
      {copyButton}
    </div>
  )
}

// Tiny, dependency-free syntax tokenizer for the CodeSnippet component.
// Supports the four languages a component library demos most: bash, css, js, ts.
// It is intentionally not a full parser — a single left-to-right scan, first
// matching rule wins, anything unmatched is emitted as plain text. Highlighting
// is presentational, so over-/under-matching only affects colour, never meaning.

export type CodeLang = 'bash' | 'css' | 'js' | 'ts'

export interface Token {
  /** A token class (`comment`, `string`, …) or `text` for unhighlighted runs. */
  type: string
  value: string
}

interface Rule {
  type: string
  re: RegExp
}

function compile(specs: ReadonlyArray<readonly [string, string]>): Rule[] {
  return specs.map(([type, source]) => ({ type, re: new RegExp(`^(?:${source})`) }))
}

const STRING = `"(?:[^"\\\\]|\\\\.)*"|'(?:[^'\\\\]|\\\\.)*'`
const TEMPLATE = '`(?:[^`\\\\]|\\\\.)*`'
const JS_KEYWORDS =
  'const|let|var|function|return|if|else|for|while|do|switch|case|break|continue|new|class|extends|super|import|export|from|default|async|await|yield|typeof|instanceof|in|of|void|delete|this|null|true|false|undefined'
const TS_KEYWORDS = `${JS_KEYWORDS}|interface|type|as|readonly|enum|implements|public|private|protected|abstract|namespace|declare|satisfies|keyof|infer|is|string|number|boolean|unknown|never|any`

const RULES: Record<CodeLang, Rule[]> = {
  bash: compile([
    ['comment', '#[^\\n]*'],
    ['string', STRING],
    ['prompt', '\\$(?= )'],
    [
      'keyword',
      '\\b(?:npx|npm|pnpm|yarn|bun|deno|node|git|cd|ls|cat|echo|export|sudo|mkdir|rm|cp|mv|curl|wget|chmod|source)\\b',
    ],
    ['variable', '--?[A-Za-z][\\w-]*'],
    ['number', '\\b\\d+(?:\\.\\d+)?\\b'],
  ]),
  css: compile([
    ['comment', '/\\*[\\s\\S]*?\\*/'],
    ['string', STRING],
    ['keyword', '@[\\w-]+'],
    ['variable', '--[\\w-]+'],
    ['fn', '[\\w-]+(?=\\()'],
    ['number', '#[0-9a-fA-F]{3,8}\\b|-?\\d*\\.?\\d+(?:[a-z%]+)?'],
    ['punct', '[{}();:,]'],
  ]),
  js: compile([
    ['comment', '//[^\\n]*|/\\*[\\s\\S]*?\\*/'],
    ['string', `${STRING}|${TEMPLATE}`],
    ['keyword', `\\b(?:${JS_KEYWORDS})\\b`],
    ['fn', '[A-Za-z_$][\\w$]*(?=\\()'],
    ['number', '-?\\d*\\.?\\d+'],
    ['punct', '[{}()\\[\\];:,.]|=>'],
  ]),
  ts: compile([
    ['comment', '//[^\\n]*|/\\*[\\s\\S]*?\\*/'],
    ['string', `${STRING}|${TEMPLATE}`],
    ['keyword', `\\b(?:${TS_KEYWORDS})\\b`],
    ['fn', '[A-Za-z_$][\\w$]*(?=\\()'],
    ['number', '-?\\d*\\.?\\d+'],
    ['punct', '[{}()\\[\\];:,.]|=>'],
  ]),
}

export function tokenize(code: string, lang: CodeLang): Token[] {
  const rules = RULES[lang]
  const tokens: Token[] = []
  let rest = code
  let plain = ''
  const flush = () => {
    if (plain) {
      tokens.push({ type: 'text', value: plain })
      plain = ''
    }
  }
  while (rest.length > 0) {
    let matched = false
    for (const { type, re } of rules) {
      const m = re.exec(rest)
      if (m && m[0].length > 0) {
        flush()
        tokens.push({ type, value: m[0] })
        rest = rest.slice(m[0].length)
        matched = true
        break
      }
    }
    if (!matched) {
      plain += rest[0]
      rest = rest.slice(1)
    }
  }
  flush()
  return tokens
}

@layer cascivo.component {
  .root {
    position: relative;

    &[data-variant='inline'] {
      display: inline-flex;
      align-items: center;
      gap: var(--cascivo-space-1);
    }
  }

  .inlineCode {
    font-family: var(--cascivo-font-mono);
    font-size: 0.875em;
    color: var(--cascivo-color-text);
    background: var(--cascivo-color-bg-subtle);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-control);
    padding-inline: var(--cascivo-space-1);
    padding-block: 0.125em;
  }

  .pre {
    margin: 0;
    padding: var(--cascivo-space-4);
    padding-inline-end: var(--cascivo-space-10);
    font-family: var(--cascivo-font-mono);
    font-size: var(--cascivo-text-sm);
    line-height: var(--cascivo-leading-relaxed);
    color: var(--cascivo-color-text);
    background: var(--cascivo-color-bg-subtle);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-surface);
    overflow-x: auto;

    .root[data-variant='single'] & {
      white-space: pre;
    }
    .root[data-variant='multi'] & {
      white-space: pre;
    }
  }

  .code {
    font: inherit;
    color: inherit;
  }

  .line {
    display: flex;
    gap: var(--cascivo-space-4);
  }

  .lineNumber {
    flex: none;
    inline-size: 2ch;
    text-align: end;
    color: var(--cascivo-color-text-subtle);
    user-select: none;
  }

  .lineText {
    white-space: pre;
  }

  .copy {
    position: absolute;
    inset-block-start: var(--cascivo-space-2);
    inset-inline-end: var(--cascivo-space-2);
    display: flex;
    align-items: center;
    justify-content: center;
    inline-size: 1.75rem;
    block-size: 1.75rem;
    padding: 0;
    color: var(--cascivo-color-text-muted);
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-control);
    cursor: pointer;
    transition:
      color var(--cascivo-duration-150) var(--cascivo-ease-out),
      background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    &:hover {
      color: var(--cascivo-color-text);
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
    }

    &[data-state='copied'] {
      color: var(--cascivo-color-success, var(--cascivo-color-accent));
    }

    .root[data-variant='inline'] & {
      position: static;
      inline-size: 1.25rem;
      block-size: 1.25rem;
    }
  }

  .icon {
    inline-size: 1rem;
    block-size: 1rem;
  }

  /* ── Syntax highlighting (theme-aware; override the --cs-* vars to retheme) ── */
  .code [data-tok='comment'] {
    color: var(--cs-comment, var(--cascivo-color-text-muted));
    font-style: italic;
  }

  .code [data-tok='string'] {
    color: var(--cs-string, var(--cascivo-color-success));
  }

  .code [data-tok='keyword'] {
    color: var(--cs-keyword, var(--cascivo-color-accent));
  }

  .code [data-tok='fn'] {
    color: var(--cs-fn, var(--cascivo-color-info));
  }

  .code [data-tok='number'] {
    color: var(--cs-number, var(--cascivo-color-warning));
  }

  .code [data-tok='variable'] {
    color: var(--cs-variable, var(--cascivo-color-accent-hover));
  }

  .code [data-tok='punct'] {
    color: var(--cs-punct, var(--cascivo-color-text-subtle));
  }

  .code [data-tok='prompt'] {
    color: var(--cs-prompt, var(--cascivo-color-text-subtle));
    user-select: none;
  }

  /* ── Terminal window chrome ─────────────────────────────── */
  .root[data-terminal] {
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-surface);
    overflow: hidden;
  }

  .bar {
    display: flex;
    align-items: center;
    gap: var(--cascivo-space-3);
    padding-inline: var(--cascivo-space-3);
    padding-block: var(--cascivo-space-2);
    background: var(--cascivo-color-surface);
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .dots {
    display: inline-flex;
    gap: 0.375rem;
  }

  .dot {
    inline-size: 0.7rem;
    block-size: 0.7rem;
    border-radius: var(--cascivo-radius-full);
    background: var(--cascivo-color-border);
  }

  .dot:nth-child(1) {
    background: #ff5f57;
  }

  .dot:nth-child(2) {
    background: #febc2e;
  }

  .dot:nth-child(3) {
    background: #28c840;
  }

  .title {
    font-family: var(--cascivo-font-mono);
    font-size: var(--cascivo-text-xs);
    color: var(--cascivo-color-text-muted);
  }

  /* In terminal mode the bar owns the top edge; the body and copy button tuck in. */
  .root[data-terminal] .pre {
    border: none;
    border-radius: 0;
  }

  .root[data-terminal] .copy {
    inset-block-start: 0.4rem;
    background: transparent;
    border-color: transparent;
  }
}
